#!/usr/bin/env python3
# TurnIt-IDE Phase 1 scaffold
# Run from repo root: python3 decode_ide_p1.py
import base64, os

ROOT = "."
def w(p, d):
    f = os.path.join(ROOT, p)
    dd = os.path.dirname(f)
    if dd: os.makedirs(dd, exist_ok=True)
    open(f, "wb").write(base64.b64decode(d))
    print(f"  WROTE  {p}")

print("=== TurnIt-IDE Phase 1 ===")

w('app/src/main/java/com/turnit/ide/ui/IdeTheme.kt', "")
w('app/src/main/java/com/turnit/ide/engine/DownloadEngine.kt', "")
w('app/src/main/java/com/turnit/ide/engine/ExtractionEngine.kt', "")
w('app/src/main/java/com/turnit/ide/ui/SetupScreen.kt', "")
w('app/src/main/java/com/turnit/ide/ui/MainShellScreen.kt', "")

print()
print("=== 5 files written ===")
print("CRITICAL: Add lib7zr.so to app/src/main/jniLibs/arm64-v8a/")
